15	//! Clipboard harvest — capture every arboard-accessible clipboard flavor
16	//! verbatim to `{N}-in.{tag}.{ext}` files in the journal directory
17	//! (typically `$HOME/apcjd/`) on every focus with changed content. The `tag`
18	//! is the classifier's verdict (`clinical` or `nonclinical`); the full
19	//! filename is e.g. `10000-in.clinical.txt`, `10000-in.nonclinical.html`.
20	//! On the Clinical branch, the focus handler pairs each capture with a
21	//! `{N}-out.txt` anonymized copy written by `apcap_main`. PHI-at-rest stays
22	//! outside the repo; anonymization and promotion to test fixtures are
23	//! manual. The destination is supplied by the caller; see
24	//! `apcrj_journal::apcrj_journal_path`. This module does not emit — errors
25	//! are returned to the caller for routing via `apcrl_*`.
26	
27	use std::fs;
28	use std::io::Write;
29	use std::path::Path;
30	
31	pub const APCRH_HARVEST_SEED_INDEX: u32 = 10000;
32	
33	/// Classifier verdict used to tag harvest filenames. The tag is decided by
34	/// the caller *before* harvest runs, not inferred from filename later.
35	#[derive(Copy, Clone, Debug, PartialEq, Eq)]
36	pub enum apcrh_Classification {
37	    Clinical,
38	    NonClinical,
39	}
40	
41	impl apcrh_Classification {
42	    /// Filename infix written between `-in.` and the extension.
43	    pub fn apcrh_tag(self) -> &'static str {
44	        match self {
45	            apcrh_Classification::Clinical    => "clinical",
46	            apcrh_Classification::NonClinical => "nonclinical",
47	        }
48	    }
49	}
50	
51	/// Capture every arboard-accessible clipboard flavor into
52	/// `{N}-in.{tag}.{ext}` files in `dir`, where `tag` is `classification`'s
53	/// filename infix. Returns the N used. N seeds at
54	/// `APCRH_HARVEST_SEED_INDEX` when `dir` is empty, otherwise
55	/// `max_leading_digit_run + 1` across any filenames that begin with digits
56	/// (legacy bare `{N}.{ext}`, prior `{N}-in.{ext}`, `{N}-out.{ext}`, and new
57	/// `{N}-in.{tag}.{ext}` all count). The directory is created lazily. Text
58	/// is required; HTML is opportunistic — absence of HTML on the clipboard is
59	/// not an error.
60	pub fn apcrh_capture_all_flavors(
61	    dir: &Path,
62	    classification: apcrh_Classification,
63	) -> Result<u32, String> {
64	    fs::create_dir_all(dir)
65	        .map_err(|e| format!("create harvest dir {}: {}", dir.display(), e))?;
66	
67	    let index = zapcrh_scan_next_index(dir)?;
68	    let tag = classification.apcrh_tag();
69	
70	    let mut clipboard = arboard::Clipboard::new()
71	        .map_err(|e| format!("clipboard open: {}", e))?;
72	
73	    let text = clipboard.get_text()
74	        .map_err(|e| format!("clipboard get_text: {}", e))?;
75	    zapcrh_write_text(dir, index, tag, &text)?;
76	
77	    // HTML is opportunistic — absence on the clipboard is expected for some
78	    // sources, not an error. Capture when present, skip otherwise.
79	    if let Ok(html) = clipboard.get().html() {
80	        zapcrh_write_html(dir, index, tag, &html)?;
81	    }
82	
83	    Ok(index)
84	}
85	
86	/// Scan `dir` for files whose name begins with a digit run and return
87	/// `max+1`, or `APCRH_HARVEST_SEED_INDEX` when none are found. Files whose
88	/// name does not start with a digit (e.g. `apcap.log`, `README`) are
89	/// ignored, as are subdirectories. Gaps are not filled — the scan advances
90	/// past the current maximum. The leading-digit parse makes mixed naming
91	/// styles — legacy bare `{N}.{ext}`, prior `{N}-in.{ext}`, `{N}-out.{ext}`,
92	/// and new `{N}-in.{tag}.{ext}` — all count toward the same index space.
93	pub(crate) fn zapcrh_scan_next_index(dir: &Path) -> Result<u32, String> {
94	    let entries = fs::read_dir(dir)
95	        .map_err(|e| format!("read harvest dir {}: {}", dir.display(), e))?;
96	
97	    let mut max: Option<u32> = None;
98	    for entry in entries {
99	        let entry = entry
100	            .map_err(|e| format!("read harvest entry: {}", e))?;
101	        if !entry.file_type().map(|t| t.is_file()).unwrap_or(false) {
102	            continue;
103	        }
104	        let path = entry.path();
105	        let name = match path.file_name().and_then(|s| s.to_str()) {
106	            Some(s) => s,
107	            None    => continue,
108	        };
109	        let digits: String = name.chars().take_while(|c| c.is_ascii_digit()).collect();
110	        if digits.is_empty() {
111	            continue;
112	        }
113	        if let Ok(n) = digits.parse::<u32>() {
114	            max = Some(max.map_or(n, |m| m.max(n)));
115	        }
116	    }
117	
118	    Ok(match max {
119	        Some(n) => n.saturating_add(1),
120	        None    => APCRH_HARVEST_SEED_INDEX,
121	    })
122	}
123	
124	/// Write the text flavor to `{index}-in.{tag}.txt` in `dir`.
125	pub(crate) fn zapcrh_write_text(dir: &Path, index: u32, tag: &str, text: &str) -> Result<(), String> {
126	    let path = dir.join(format!("{}-in.{}.txt", index, tag));
127	    let mut file = fs::File::create(&path)
128	        .map_err(|e| format!("create {}: {}", path.display(), e))?;
129	    file.write_all(text.as_bytes())
130	        .map_err(|e| format!("write {}: {}", path.display(), e))?;
131	    Ok(())
132	}
133	
134	/// Write the HTML flavor to `{index}-in.{tag}.html` in `dir`.
135	pub(crate) fn zapcrh_write_html(dir: &Path, index: u32, tag: &str, html: &str) -> Result<(), String> {
136	    let path = dir.join(format!("{}-in.{}.html", index, tag));
137	    let mut file = fs::File::create(&path)
138	        .map_err(|e| format!("create {}: {}", path.display(), e))?;
139	    file.write_all(html.as_bytes())
140	        .map_err(|e| format!("write {}: {}", path.display(), e))?;
141	    Ok(())
142	}
