8	//
9	// Unless required by applicable law or agreed to in writing, software
10	// distributed under the License is distributed on an "AS IS" BASIS,
11	// WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
12	// See the License for the specific language governing permissions and
13	// limitations under the License.
14	
15	#![deny(warnings)]
16	#![allow(non_camel_case_types)]
17	#![allow(private_interfaces)]
18	#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]
19	
20	// RCG output discipline: all emission via apcrl_*! — no direct println!/eprintln!
21	
22	use std::sync::{Mutex, OnceLock};
23	use apcd::apcrm_match::{apcrm_Finding, apcrm_Severity, apcrm_PhiCategory};
24	
25	// ---------------------------------------------------------------------------
26	// Statics — dictionary cache, clipboard tracking, toggle state
27	// ---------------------------------------------------------------------------
28	
29	static ZAPCAP_DICTS: OnceLock<apcd::apcrd_dictionaries::apcrd_Dictionaries> = OnceLock::new();
30	static ZAPCAP_LAST_CLIPBOARD: Mutex<Option<String>> = Mutex::new(None);
31	static ZAPCAP_LAST_CLINICAL: Mutex<Option<zapcap_ClinicalCache>> = Mutex::new(None);
32	static ZAPCAP_TOGGLE_STATES: Mutex<Vec<String>> = Mutex::new(Vec::new());
33	
34	struct zapcap_ClinicalCache {
35	    findings:   Vec<apcrm_Finding>,
36	    plain_text: String,
37	}
38	
39	// ---------------------------------------------------------------------------
40	// Focus handler — read clipboard, run detection, push rendered HTML
41	// ---------------------------------------------------------------------------
42	
43	fn zapcap_handle_focus(window: &tauri::WebviewWindow) -> Result<(), String> {
44	    let mut clipboard = arboard::Clipboard::new()
45	        .map_err(|e| format!("clipboard error: {}", e))?;
46	
47	    let content = clipboard.get_text()
48	        .map_err(|e| format!("clipboard error: {}", e))?;
49	
50	    apcd::apcrl_info_now!("focus: {} bytes", content.len());
51	
52	    // Change detection — same content as last invocation → preserve UI state
53	    {
54	        let last = ZAPCAP_LAST_CLIPBOARD.lock()
55	            .map_err(|e| format!("lock error: {}", e))?;
56	        if last.as_deref() == Some(content.as_str()) {
57	            apcd::apcrl_info_now!("focus: unchanged");
58	            return Ok(());
59	        }
60	    }
61	
62	    let dicts = ZAPCAP_DICTS.get_or_init(apcd::apcrd_dictionaries::apcrd_Dictionaries::apcrd_load);
63	
64	    let result = apcd::apcre_engine::apcre_analyze(&content, dicts);
65	
66	    // Classification is decided before harvest runs — the tag in the
67	    // filename records what the classifier said at the moment of capture,
68	    // not some later inference.
69	    let classification = match &result {
70	        apcd::apcre_engine::apcre_Result::Clinical { .. } =>
71	            apcd::apcrh_harvest::apcrh_Classification::Clinical,
72	        apcd::apcre_engine::apcre_Result::NonClinical { .. } =>
73	            apcd::apcrh_harvest::apcrh_Classification::NonClinical,
74	    };
75	
76	    // Harvest runs for every focus with changed content. Non-clinical
77	    // captures land alongside clinical ones in the journal so a
78	    // classification failure still leaves an artifact to post-mortem.
79	    let journal_dir = apcd::apcrj_journal::apcrj_journal_path();
80	    let harvest_index: Option<u32> = match &journal_dir {
81	        Some(dir) => {
82	            match apcd::apcrh_harvest::apcrh_capture_all_flavors(dir, classification) {
83	                Ok(n) => {
84	                    apcd::apcrl_info_now!("harvest captured as {}", n);
85	                    Some(n)
86	                }
87	                Err(e) => {
88	                    apcd::apcrl_error_now!("harvest capture failed: {}", e);
89	                    None
90	                }
91	            }
92	        }
93	        None => {
94	            apcd::apcrl_error_now!("harvest skipped: HOME not set");
95	            None
96	        }
97	    };
98	
99	    match result {
100	        apcd::apcre_engine::apcre_Result::Clinical { findings, plain_text } => {
101	            apcd::apcrl_info_now!("clinical: {} findings", findings.len());
102	
103	            // Pair the input capture with a default-elide anonymized output.
104	            // Output-at-focus uses an empty toggle-states slice —
105	            // apcre_anonymize defaults to elide for missing entries —
106	            // producing what Ann would get if she copied without touching
107	            // any toggles. Per-toggle refresh of the output file is a
108	            // deferred UX pace; this pairing is about legible debug signal.
109	            // If harvest failed, we have no N to pair with — skip the out
110	            // write rather than invent an index.
111	            if let (Some(dir), Some(n)) = (journal_dir.as_ref(), harvest_index) {
112	                let anonymized = apcd::apcre_engine::apcre_anonymize(
113	                    &plain_text, &findings, &[],
114	                );
115	                let out_path = dir.join(format!("{}-out.txt", n));
116	                match std::fs::write(&out_path, &anonymized) {
117	                    Ok(()) => apcd::apcrl_info_now!(
118	                        "anonymized written as {}-out.txt", n
119	                    ),
120	                    Err(e) => apcd::apcrl_error_now!(
121	                        "anonymized write failed: {}", e
122	                    ),
123	                }
124	            }
125	
126	            // Clear system clipboard only after consuming clinical content.
127	            // Non-clinical captures do not disturb Ann's clipboard state.
128	            let _ = clipboard.set_text(String::new());
129	
130	            {
131	                let mut last = ZAPCAP_LAST_CLIPBOARD.lock()
132	                    .map_err(|e| format!("lock error: {}", e))?;
133	                *last = Some(String::new());
134	            }
135	
136	            {
137	                let mut toggle_states = ZAPCAP_TOGGLE_STATES.lock()
138	                    .map_err(|e| format!("lock error: {}", e))?;
139	                *toggle_states = vec!["elide".to_string(); findings.len()];
140	            }
141	
142	            {
143	                let mut cache = ZAPCAP_LAST_CLINICAL.lock()
144	                    .map_err(|e| format!("lock error: {}", e))?;
145	                *cache = Some(zapcap_ClinicalCache { findings, plain_text });
146	            }
147	
148	            zapcap_push_triage(window)
149	        }
150	        apcd::apcre_engine::apcre_Result::NonClinical { content_length, content_type, preview } => {
151	            apcd::apcrl_info_now!("non-clinical: {} ({} bytes)", content_type, content_length);
152	            {
153	                let mut last = ZAPCAP_LAST_CLIPBOARD.lock()
154	                    .map_err(|e| format!("lock error: {}", e))?;
155	                *last = Some(content);
156	            }
157	
158	            {
159	                let mut cache = ZAPCAP_LAST_CLINICAL.lock()
160	                    .map_err(|e| format!("lock error: {}", e))?;
161	                *cache = None;
162	            }
163	
164	            {
165	                let mut toggle_states = ZAPCAP_TOGGLE_STATES.lock()
166	                    .map_err(|e| format!("lock error: {}", e))?;
167	                *toggle_states = Vec::new();
168	            }
169	
170	            let diagnostic = format!(
171	                "Not clinical ({} bytes, {}): {}",
172	                content_length, content_type, preview
173	            );
174	            zapcap_push_instruction(window, &diagnostic)
175	        }
176	    }
177	}
178	
179	// ---------------------------------------------------------------------------
180	// Tauri commands — toggle finding, copy anonymized
181	// ---------------------------------------------------------------------------
182	
183	#[tauri::command]
184	fn toggle_finding(index: usize, window: tauri::WebviewWindow) -> Result<(), String> {
185	    {
186	        let mut states = ZAPCAP_TOGGLE_STATES.lock()
187	            .map_err(|e| format!("lock error: {}", e))?;
188	        if index < states.len() {
189	            states[index] = if states[index] == "elide" {
190	                "pass".to_string()
191	            } else {
192	                "elide".to_string()
193	            };
194	        }
195	    }
196	    zapcap_push_triage(&window)
197	}
198	
199	#[tauri::command]
200	fn copy_anonymized(window: tauri::WebviewWindow) -> Result<(), String> {
201	    let toggle_states = ZAPCAP_TOGGLE_STATES.lock()
202	        .map_err(|e| format!("lock error: {}", e))?
203	        .clone();
204	
205	    let anonymized = {
206	        let cache = ZAPCAP_LAST_CLINICAL.lock()
207	            .map_err(|e| format!("lock error: {}", e))?;
208	        let clinical = cache.as_ref()
209	            .ok_or_else(|| "no clinical data to anonymize".to_string())?;
210	        apcd::apcre_engine::apcre_anonymize(
211	            &clinical.plain_text,
212	            &clinical.findings,
213	            &toggle_states,
214	        )
215	    };
216	
217	    let mut clipboard = arboard::Clipboard::new()
218	        .map_err(|e| format!("clipboard error: {}", e))?;
219	    clipboard.set_text(anonymized)
220	        .map_err(|e| format!("clipboard error: {}", e))?;
221	
222	    zapcap_push_triage_with_feedback(&window, "Copied!")?;
223	
224	    let win = window.clone();
225	    std::thread::spawn(move || {
226	        std::thread::sleep(std::time::Duration::from_secs(2));
227	        let _ = zapcap_push_triage(&win);
228	    });
229	
230	    Ok(())
231	}
232	
233	// ---------------------------------------------------------------------------
234	// HTML push — render state and inject into webview
235	// ---------------------------------------------------------------------------
236	
237	fn zapcap_push_instruction(window: &tauri::WebviewWindow, diagnostic: &str) -> Result<(), String> {
238	    let html = zapcap_render_instruction(diagnostic);
239	    zapcap_eval_html(window, &html)
240	}
241	
242	fn zapcap_push_triage(window: &tauri::WebviewWindow) -> Result<(), String> {
243	    zapcap_push_triage_with_feedback(window, "Copy Anonymized to Clipboard")
244	}
245	
246	fn zapcap_push_triage_with_feedback(
247	    window: &tauri::WebviewWindow,
248	    btn_text: &str,
249	) -> Result<(), String> {
250	    // Clone data out of locks to avoid holding multiple locks simultaneously
251	    let (findings, plain_text) = {
252	        let cache = ZAPCAP_LAST_CLINICAL.lock()
253	            .map_err(|e| format!("lock error: {}", e))?;
254	        let clinical = cache.as_ref()
255	            .ok_or_else(|| "no clinical data for triage".to_string())?;
256	        (clinical.findings.clone(), clinical.plain_text.clone())
257	    };
258	    let toggle_states = ZAPCAP_TOGGLE_STATES.lock()
259	        .map_err(|e| format!("lock error: {}", e))?
260	        .clone();
261	
262	    let html = zapcap_render_triage(&findings, &plain_text, &toggle_states, btn_text);
263	    zapcap_eval_html(window, &html)
264	}
265	
266	fn zapcap_eval_html(window: &tauri::WebviewWindow, html: &str) -> Result<(), String> {
267	    let escaped = zapcap_js_string_literal(html);
268	    window.eval(&format!("document.getElementById('app').innerHTML={}", escaped))
269	        .map_err(|e| format!("eval error: {}", e))
270	}
271	
272	// ---------------------------------------------------------------------------
273	// HTML rendering — instruction state
274	// ---------------------------------------------------------------------------
275	
276	fn zapcap_render_instruction(diagnostic: &str) -> String {
277	    format!(
278	        "<h1>Ann&rsquo;s PHI Clipbuddy</h1>\
279	         <p class=\"instruction\">Copy a clinical note from Epic using \
280	         &ldquo;Copy All&rdquo;, then switch to this window.</p>\
281	         <p class=\"diagnostic\">{}</p>",
282	        zapcap_escape_html(diagnostic)
283	    )
284	}
285	
286	// ---------------------------------------------------------------------------
287	// HTML rendering — triage state
288	// ---------------------------------------------------------------------------
289	
290	fn zapcap_render_triage(
291	    findings: &[apcrm_Finding],
292	    plain_text: &str,
293	    toggle_states: &[String],
294	    btn_text: &str,
295	) -> String {
296	    let preview = zapcap_render_preview(findings, plain_text, toggle_states);
297	    let (yellow_html, red_html) = zapcap_render_findings(findings, toggle_states);
298	
299	    format!(
300	        "<h1>Ann&rsquo;s PHI Clipbuddy</h1>\
301	         <div id=\"document-preview\">{}</div>\
302	         <div id=\"findings-panel\">\
303	         <div class=\"findings-section\" id=\"findings-yellow\">\
304	         <h3>Questionable Findings</h3>\
305	         <div class=\"findings-list\" id=\"yellow-list\">{}</div></div>\
306	         <div class=\"findings-section\" id=\"findings-red\">\
307	         <h3>Definite PHI</h3>\
308	         <div class=\"findings-list\" id=\"red-list\">{}</div></div></div>\
309	         <button id=\"copy-btn\" \
310	         onclick=\"window.__TAURI__.core.invoke('copy_anonymized')\">{}</button>",
311	        preview, yellow_html, red_html, zapcap_escape_html(btn_text)
312	    )
313	}
314	
315	// ---------------------------------------------------------------------------
316	// HTML rendering — document preview with inline PHI highlights
317	// ---------------------------------------------------------------------------
318	
319	fn zapcap_render_preview(
320	    findings: &[apcrm_Finding],
321	    plain_text: &str,
322	    toggle_states: &[String],
323	) -> String {
324	    // Build index-annotated list sorted by offset (byte offsets used directly)
325	    let mut sorted: Vec<(usize, &apcrm_Finding)> = findings.iter().enumerate().collect();
326	    sorted.sort_by(|a, b| a.1.offset.cmp(&b.1.offset).then(b.1.length.cmp(&a.1.length)));
327	
328	    let mut parts = Vec::new();
329	    let mut pos: usize = 0;
330	
331	    for (idx, f) in &sorted {
332	        if f.offset < pos { continue; } // skip overlap
333	
334	        // Text before this finding
335	        if f.offset > pos {
336	            parts.push(zapcap_escape_html(&plain_text[pos..f.offset]));
337	        }
338	
339	        // Finding span — byte offsets consumed directly, no conversion needed
340	        let end = f.offset + f.length;
341	        let cls = if toggle_states.get(*idx).map(|s| s.as_str()) == Some("pass") {
342	            "phi-pass"
343	        } else if f.severity == apcrm_Severity::Red {
344	            "phi-red"
345	        } else {
346	            "phi-yellow"
347	        };
348	
349	        parts.push(format!(
350	            "<span class=\"{}\" data-index=\"{}\">{}</span>",
351	            cls, idx, zapcap_escape_html(&plain_text[f.offset..end])
352	        ));
353	        pos = end;
354	    }
355	
356	    // Remaining text
357	    if pos < plain_text.len() {
358	        parts.push(zapcap_escape_html(&plain_text[pos..]));
359	    }
360	
361	    parts.join("")
362	}
363	
364	// ---------------------------------------------------------------------------
365	// HTML rendering — findings panel (yellow + red sections)
366	// ---------------------------------------------------------------------------
367	
368	fn zapcap_render_findings(
369	    findings: &[apcrm_Finding],
370	    toggle_states: &[String],
371	) -> (String, String) {
372	    let mut yellow = Vec::new();
373	    let mut red = Vec::new();
374	
375	    for (i, f) in findings.iter().enumerate() {
376	        let state = toggle_states.get(i).map(|s| s.as_str()).unwrap_or("elide");
377	        let label = zapcap_format_category(f.category);
378	        let btn_text = if state == "elide" { "ELIDE \u{25bc}" } else { "PASS \u{25bc}" };
379	
380	        let entry = format!(
381	            "<div class=\"finding-entry\">\
382	             <span class=\"finding-text\">{}</span>\
383	             <span class=\"finding-category\">{}</span>\
384	             <button class=\"finding-toggle {}\" \
385	             onclick=\"window.__TAURI__.core.invoke('toggle_finding',{{index:{}}})\"\
386	             >{}</button></div>",
387	            zapcap_escape_html(&f.text),
388	            label,
389	            state,
390	            i,
391	            btn_text
392	        );
393	
394	        if f.severity == apcrm_Severity::Yellow {
395	            yellow.push(entry);
396	        } else {
397	            red.push(entry);
398	        }
399	    }
400	
401	    let yellow_html = if yellow.is_empty() {
402	        "<div class=\"empty-section\">None detected</div>".to_string()
403	    } else {
404	        yellow.join("")
405	    };
406	
407	    let red_html = if red.is_empty() {
408	        "<div class=\"empty-section\">None detected</div>".to_string()
409	    } else {
410	        red.join("")
411	    };
412	
413	    (yellow_html, red_html)
414	}
415	
416	// ---------------------------------------------------------------------------
417	// Utilities
418	// ---------------------------------------------------------------------------
419	
420	fn zapcap_format_category(cat: apcrm_PhiCategory) -> &'static str {
421	    match cat {
422	        apcrm_PhiCategory::Name         => "NAME",
423	        apcrm_PhiCategory::Provider     => "PROVIDER",
424	        apcrm_PhiCategory::Facility     => "FACILITY",
425	        apcrm_PhiCategory::Date         => "DATE",
426	        apcrm_PhiCategory::Dob          => "DOB",
427	        apcrm_PhiCategory::Phone        => "PHONE",
428	        apcrm_PhiCategory::Email        => "EMAIL",
429	        apcrm_PhiCategory::Ssn          => "SSN",
430	        apcrm_PhiCategory::Mrn          => "MRN",
431	        apcrm_PhiCategory::Account      => "ACCOUNT",
432	        apcrm_PhiCategory::EncounterId  => "ENCOUNTER ID",
433	        apcrm_PhiCategory::Address      => "ADDRESS",
434	        apcrm_PhiCategory::HealthPlanId => "HEALTH PLAN ID",
435	        apcrm_PhiCategory::DeviceId     => "DEVICE ID",
436	        apcrm_PhiCategory::Npi          => "NPI",
437	        apcrm_PhiCategory::Dea          => "DEA",
438	        apcrm_PhiCategory::Url          => "URL",
439	        apcrm_PhiCategory::IpAddress    => "IP ADDRESS",
440	    }
441	}
442	
443	fn zapcap_escape_html(text: &str) -> String {
444	    text.replace('&', "&amp;")
445	        .replace('<', "&lt;")
446	        .replace('>', "&gt;")
447	        .replace('"', "&quot;")
448	}
449	
450	fn zapcap_js_string_literal(s: &str) -> String {
451	    let mut out = String::with_capacity(s.len() + 2);
452	    out.push('"');
453	    for c in s.chars() {
454	        match c {
455	            '\\'     => out.push_str("\\\\"),
456	            '"'      => out.push_str("\\\""),
457	            '\n'     => out.push_str("\\n"),
458	            '\r'     => out.push_str("\\r"),
459	            '\t'     => out.push_str("\\t"),
460	            '\u{08}' => out.push_str("\\b"),
461	            '\u{0C}' => out.push_str("\\f"),
462	            '\u{2028}' => out.push_str("\\u2028"),
463	            '\u{2029}' => out.push_str("\\u2029"),
464	            c if (c as u32) < 0x20 => out.push_str(&format!("\\u{:04x}", c as u32)),
465	            c => out.push(c),
466	        }
467	    }
468	    out.push('"');
469	    out
470	}
471	
472	// ---------------------------------------------------------------------------
473	// Entry point
474	// ---------------------------------------------------------------------------
475	
476	fn zapcap_init_log_tee() {
477	    let log_path = match apcd::apcrj_journal::apcrj_log_path() {
478	        Some(p) => p,
479	        None    => {
480	            apcd::apcrl_error_now!("log tee skipped: HOME not set");
481	            return;
482	        }
483	    };
484	    if let Some(parent) = log_path.parent() {
485	        if let Err(e) = std::fs::create_dir_all(parent) {
486	            apcd::apcrl_error_now!(
487	                "create journal dir {}: {}", parent.display(), e
488	            );
489	            return;
490	        }
491	    }
492	    if let Err(e) = apcd::apcrl_log::apcrl_tee_init(&log_path) {
493	        apcd::apcrl_error_now!("log tee init failed: {}", e);
494	    }
495	}
496	
497	fn main() {
498	    zapcap_init_log_tee();
499	    apcd::apcrl_info_now!("starting Ann's PHI Clipbuddy");
500	    // Self-update watcher disabled for prototype — manual quit + relaunch
501	    // via /Users/Shared/apcua/Apcap.app is the current deploy workflow.
502	    // apcd::apcru_update::apcru_start_watcher();
503	    tauri::Builder::default()
504	        .invoke_handler(tauri::generate_handler![toggle_finding, copy_anonymized])
505	        .setup(|app| {
506	            use tauri::Manager;
507	            let window = app.get_webview_window("main")
508	                .expect("main window must exist");
509	            let win = window.clone();
510	            window.on_window_event(move |event| {
511	                if let tauri::WindowEvent::Focused(true) = event {
512	                    if let Err(e) = zapcap_handle_focus(&win) {
513	                        apcd::apcrl_error_now!("focus handler error: {}", e);
514	                    }
515	                }
516	            });
517	            Ok(())
518	        })
519	        .run(tauri::generate_context!())
520	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("tauri application error: {}", e));
521	}
