15	//! Logging infrastructure — severity-named macros with auto file/line capture.
16	//!
17	//! All application logging goes through `apcrl_*_now!`, `apcrl_*_if!`, and
18	//! comparison variants. No naked `println!`/`eprintln!` elsewhere in the codebase.
19	//!
20	//! Output is line-oriented to stdout. Format:
21	//!   `[LEVEL] [YYYY-MM-DD HH:MM:SS.mmm] [file:line] message`
22	//!
23	//! The timestamp is local wall-clock with millisecond precision, captured at
24	//! emit time by `chrono::Local::now()`. Level, timestamp, and file:line flow
25	//! through a single formatter so stdout and the tee sink never drift.
26	//!
27	//! An optional file-tee sink can be installed via `apcrl_tee_init` once at
28	//! application startup. When present, every emission is appended to the tee
29	//! file in the exact format that goes to stdout — one format, two sinks. Tee
30	//! write failures are swallowed to avoid recursive-logging hazards; stdout
31	//! remains authoritative.
32	//!
33	//! Suffix families:
34	//!   `_now`  — unconditional emission
35	//!   `_if`   — boolean conditional, returns the bool
36	//!   `_eq`, `_ne`, `_lt`, `_gt`, `_le`, `_ge` — comparison conditional,
37	//!            stringifies arguments, returns the bool
38	
39	use std::fs::{File, OpenOptions};
40	use std::io::Write;
41	use std::path::Path;
42	use std::sync::{Mutex, OnceLock};
43	
44	pub const APCRL_LEVEL_TRACE: &str = "[TRACE]";
45	pub const APCRL_LEVEL_INFO:  &str = "[INFO]";
46	pub const APCRL_LEVEL_ERROR: &str = "[ERROR]";
47	pub const APCRL_LEVEL_FATAL: &str = "[FATAL]";
48	
49	static ZAPCRL_TEE: OnceLock<Mutex<File>> = OnceLock::new();
50	
51	/// Install a file-tee sink. Every subsequent `apcrl_*` emission is appended
52	/// to `path` in the exact format that goes to stdout. The file is opened in
53	/// append-create mode. Call once from application startup; subsequent calls
54	/// return `Err` without disturbing the active sink.
