//! Tests for `apcrk_pasteboard` — UTI-to-extension mapping and sanitizer.
//! The NSPasteboard FFI itself is not unit-testable (requires a live
//! pasteboard and main-thread AppKit context); verification of the FFI
//! path is by deployed run on Ann's machine per the pace exit criteria.

use super::apcrk_pasteboard::{apcrk_extension_for_uti, zapcrk_sanitize_uti_for_test};

#[test]
fn apctk_extension_known_public_utis() {
    assert_eq!(apcrk_extension_for_uti("public.rtf"),              "rtf");
    assert_eq!(apcrk_extension_for_uti("public.utf8-plain-text"),  "utf8.txt");
    assert_eq!(apcrk_extension_for_uti("public.utf16-plain-text"), "utf16.txt");
    assert_eq!(apcrk_extension_for_uti("public.plain-text"),       "txt");
    assert_eq!(apcrk_extension_for_uti("public.html"),             "html");
}

#[test]
fn apctk_extension_known_image_utis() {
    assert_eq!(apcrk_extension_for_uti("public.tiff"), "tiff");
    assert_eq!(apcrk_extension_for_uti("public.png"),  "png");
    assert_eq!(apcrk_extension_for_uti("public.jpeg"), "jpeg");
}

#[test]
fn apctk_extension_known_url_utis() {
    assert_eq!(apcrk_extension_for_uti("public.url"),      "url");
    assert_eq!(apcrk_extension_for_uti("public.file-url"), "fileurl");
}

#[test]
fn apctk_extension_unknown_uti_sanitizes_with_bin() {
    // Unknown but well-formed reverse-dns UTI — dots collapse to hyphens.
    assert_eq!(
        apcrk_extension_for_uti("com.example.proprietary.format"),
        "com-example-proprietary-format.bin",
    );
}

#[test]
fn apctk_extension_legacy_nspasteboard_names_go_through_sanitizer() {
    // Docket explicitly notes legacy names (`NSStringPboardType`,
    // `Unicode text`) take the sanitized-uti path rather than bespoke
    // mappings — they are not canonical flavors, just historical aliases.
    assert_eq!(
        apcrk_extension_for_uti("NSStringPboardType"),
        "NSStringPboardType.bin",
    );
    assert_eq!(
        apcrk_extension_for_uti("Unicode text"),
        "Unicode-text.bin",
    );
    assert_eq!(
        apcrk_extension_for_uti("string"),
        "string.bin",
    );
}

#[test]
fn apctk_sanitize_collapses_run_of_nonkeep_to_single_hyphen() {
    // "a...b" should not produce "a---b" — run of forbidden chars
    // collapses to one hyphen.
    assert_eq!(zapcrk_sanitize_uti_for_test("a...b"),   "a-b");
    assert_eq!(zapcrk_sanitize_uti_for_test("x / y"),   "x-y");
    assert_eq!(zapcrk_sanitize_uti_for_test("a..b..c"), "a-b-c");
}

#[test]
fn apctk_sanitize_trims_leading_and_trailing_hyphens() {
    assert_eq!(zapcrk_sanitize_uti_for_test(".leading"),      "leading");
    assert_eq!(zapcrk_sanitize_uti_for_test("trailing."),     "trailing");
    assert_eq!(zapcrk_sanitize_uti_for_test(".both.sides."),  "both-sides");
}

#[test]
fn apctk_sanitize_scrubs_forbidden_filename_chars() {
    // Path separators, shell metacharacters, and whitespace must never
    // appear in the emitted filename.
    assert_eq!(zapcrk_sanitize_uti_for_test("a/b\\c:d*e?f"), "a-b-c-d-e-f");
    assert_eq!(zapcrk_sanitize_uti_for_test("a b c"),        "a-b-c");
    assert_eq!(zapcrk_sanitize_uti_for_test("a\tb\nc"),      "a-b-c");
}

#[test]
fn apctk_sanitize_preserves_existing_hyphens_and_alphanumerics() {
    assert_eq!(
        zapcrk_sanitize_uti_for_test("com-example-foo-bar-42"),
        "com-example-foo-bar-42",
    );
}

#[test]
fn apctk_sanitize_empty_yields_placeholder() {
    // A pathological empty UTI must still produce a non-empty filename
    // token so `{index}-in.{tag}..bin` — a double-dot — never happens.
    assert_eq!(zapcrk_sanitize_uti_for_test(""),       "flavor");
    assert_eq!(zapcrk_sanitize_uti_for_test("..."),    "flavor");
    assert_eq!(zapcrk_sanitize_uti_for_test("   "),    "flavor");
}

#[test]
fn apctk_extension_unknown_uti_is_filename_safe() {
    // Property: for any input, the resulting extension contains no
    // path separators, no whitespace, no control characters.
    let samples = [
        "com.example/evil",
        "weird name with spaces",
        "tab\there",
        "dot.in.middle",
        "",
        "///",
        "x",
    ];
    for s in &samples {
        let ext = apcrk_extension_for_uti(s);
        for c in ext.chars() {
            assert!(
                c == '-' || c == '.' || c.is_ascii_alphanumeric(),
                "extension {:?} from input {:?} contains forbidden char {:?}",
                ext, s, c
            );
        }
    }
}

