/// Capture every **declared** clipboard flavor into `{N}-in.{tag}.{ext}`
/// files in `dir`, where `tag` is `classification`'s filename infix.
/// Returns the N used. N seeds at `APCRH_HARVEST_SEED_INDEX` when `dir` is
/// empty, otherwise `max_leading_digit_run + 1` across any filenames that
/// begin with digits (legacy bare `{N}.{ext}`, prior `{N}-in.{ext}`,
/// `{N}-out.{ext}`, new `{N}-in.{tag}.{ext}`, and multi-flavor
/// `{N}-in.{tag}.rtf` / `{N}-in.{tag}.utf8.txt` all count). The directory
/// is created lazily.
///
/// On macOS, enumeration goes through `apcrb_pasteboard` — each declared
/// UTI on the general pasteboard's first item is written with a
/// UTI-derived extension. When the FFI path produces zero flavors (empty
/// pasteboard, FFI error, or non-macOS build) this falls back to the
/// arboard path: plain text is required, HTML is opportunistic.
pub fn apcrh_capture_all_flavors(
    dir: &Path,
    classification: apcrh_Classification,
) -> Result<u32, String> {
    fs::create_dir_all(dir)
        .map_err(|e| format!("create harvest dir {}: {}", dir.display(), e))?;

    let index = zapcrh_scan_next_index(dir)?;
    let tag = classification.apcrh_tag();

    // Native path: declared-flavor enumeration via apcrb_pasteboard.
    // Errors are logged inside apcrb; we only inspect the filename count to
    // decide whether to fall through to arboard. An empty Ok or Err both
    // trigger the fallback — harvest's contract to the caller is
    // "something on disk whenever the clipboard has text."
    let native_count = match crate::apcrb_pasteboard::apcrb_capture_declared_flavors(
        dir, classification, index,
    ) {
        Ok(filenames) => filenames.len(),
        Err(_)        => 0,
    };

    if native_count == 0 {
        let mut clipboard = arboard::Clipboard::new()
            .map_err(|e| format!("clipboard open: {}", e))?;

        let text = clipboard.get_text()
            .map_err(|e| format!("clipboard get_text: {}", e))?;
        zapcrh_write_text(dir, index, tag, &text)?;

        // HTML is opportunistic — absence on the clipboard is expected for
        // some sources, not an error. Capture when present, skip otherwise.
        if let Ok(html) = clipboard.get().html() {
            zapcrh_write_html(dir, index, tag, &html)?;
        }
    }

    Ok(index)
}

